# ── CSV PROCESSING ────────────────────────────────────────────────────────────

def norm_id(s):
    return re.sub(r"[^a-z0-9]", "", str(s).lower())


def load_feed_works_csv(uploaded) -> pd.DataFrame:
    text = uploaded.read().decode("utf-8")
    lines = text.strip().split("\n")
    hi = next((i for i, l in enumerate(lines) if "Product title" in l and "Day" in l), None)
    if hi is None:
        raise ValueError("Header row not found.")
    df = pd.read_csv(io.StringIO("\n".join(lines[hi:])))
    for col in ["Product clicks","Product impressions","Product purchases",
                "Product purchase value","Product purchase rate","Product CTR"]:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0)
    if "Traffic" in df.columns:
        df = df[df["Traffic"] == "Organic"]
    df["Day"]     = pd.to_datetime(df["Day"])
    df["id_norm"] = df["Product ID"].apply(norm_id)
    df["group"]   = df["id_norm"].map(LOOKUP)
    df = df[df["group"].notna()]
    return df


def agg_daily(df, n_opt, n_nc):
    result = {}
    for grp, n in [("opt", n_opt), ("nc", n_nc)]:
        g = df[df["group"] == grp].groupby("Day").agg(
            clicks=("Product clicks", "sum"),
            impr=("Product impressions", "sum"),
            purch=("Product purchases", "sum"),
            val=("Product purchase value", "sum"),
            pr_sum=("Product purchase rate", "sum"),
            pr_rows=("Product purchase rate", "count"),
        ).reset_index().sort_values("Day")
        g["clicks_pp"] = g["clicks"] / n
        g["impr_pp"]   = g["impr"] / n
        g["purch_pp"]  = g["purch"] / n
        g["val_pp"]    = g["val"] / n
        g["ctr"] = (g["clicks"] / g["impr"].replace(0, float("nan"))) * 100
        g["pr"]  = (g["pr_sum"] / g["pr_rows"].replace(0, float("nan"))) * 100
        result[grp] = g.set_index("Day")
    return result


def build_structured_data(df):
    df = df[df["Day"] < df["Day"].max()].copy()
    n_opt = df[df["group"] == "opt"]["id_norm"].nunique()
    n_nc  = df[df["group"] == "nc"]["id_norm"].nunique()
    grps  = agg_daily(df, n_opt, n_nc)
    opt_d, nc_d = grps["opt"], grps["nc"]
    dates = sorted(set(opt_d.index.tolist()) & set(nc_d.index.tolist()))

    def ser(g, col):
        return [round(float(g.loc[d, col]), 4) if d in g.index and pd.notna(g.loc[d, col]) else None
                for d in dates]

    cat = df.fillna("").groupby(
        ["Product category (1st level)", "group", "Day"]
    ).agg(
        cl=("Product clicks","sum"), im=("Product impressions","sum"),
        pu=("Product purchases","sum"), va=("Product purchase value","sum"),
        prs=("Product purchase rate","sum"), prr=("Product purchase rate","count"),
        np=("id_norm","nunique"),
    ).reset_index()

    cat_records = [
        [r["Product category (1st level)"], r["group"], r["Day"].strftime("%Y-%m-%d"),
         r["cl"], r["im"], r["pu"], r["va"], r["prs"], int(r["prr"]), int(r["np"])]
        for _, r in cat.iterrows()
    ]

    return {
        "labels": [d.strftime("%d %b") for d in dates],
        "iso":    [d.strftime("%Y-%m-%d") for d in dates],
        "opt":    {"clicks":ser(opt_d,"clicks_pp"),"impr":ser(opt_d,"impr_pp"),
                   "ctr":ser(opt_d,"ctr"),"pr":ser(opt_d,"pr"),
                   "purch":ser(opt_d,"purch_pp"),"val":ser(opt_d,"val_pp")},
        "nc":     {"clicks":ser(nc_d,"clicks_pp"),"impr":ser(nc_d,"impr_pp"),
                   "ctr":ser(nc_d,"ctr"),"pr":ser(nc_d,"pr"),
                   "purch":ser(nc_d,"purch_pp"),"val":ser(nc_d,"val_pp")},
        "n_opt": n_opt, "n_nc": n_nc,
        "taxonomy": {r[0]: True for r in cat_records if r[0]},
        "cat_records": cat_records,
    }


def auto_split_years(df):
    years = sorted(df["Day"].dt.year.unique())
    if len(years) < 2:
        return df, None
    curr_yr = max(years)
    return df[df["Day"].dt.year == curr_yr].copy(), df[df["Day"].dt.year < curr_yr].copy()


def build_yoy_lookup(prior_df, n_opt, n_nc):
    prior_df = prior_df[prior_df["Day"] < prior_df["Day"].max()].copy()
    grps = agg_daily(prior_df, n_opt, n_nc)
    result = {"opt": {}, "nc": {}}
    col_map = [("clicks_pp","clicks"),("impr_pp","impr"),("ctr","ctr"),
               ("pr","pr"),("purch_pp","purch"),("val_pp","val")]
    for grp in ["opt", "nc"]:
        g = grps[grp]
        for col, key in col_map:
            result[grp][key] = {}
        for day in g.index:
            aligned = (day + timedelta(days=364)).strftime("%Y-%m-%d")
            for col, key in col_map:
                v = g.loc[day, col] if col in g.columns else None
                result[grp][key][aligned] = round(float(v), 4) if v is not None and pd.notna(v) else None
    result["date_min"] = prior_df["Day"].min().strftime("%Y-%m-%d")
    result["date_max"] = prior_df["Day"].max().strftime("%Y-%m-%d")
    return result


# ── FILTER HELPERS ────────────────────────────────────────────────────────────

def get_filtered(D, from_date, to_date, l1_filter):
    iso_f = [d for d in D["iso"] if (not from_date or d >= from_date) and (not to_date or d <= to_date)]
    lab_f = [D["labels"][D["iso"].index(d)] for d in iso_f]

    if not l1_filter:
        def pick(ser, k):
            return [ser[k][D["iso"].index(d)] if d in D["iso"] else None for d in iso_f]
        return {"labels":lab_f,"iso":iso_f,
                "opt":{k:pick(D["opt"],k) for k in D["opt"]},
                "nc":{k:pick(D["nc"],k) for k in D["nc"]},
                "n_opt":D["n_opt"],"n_nc":D["n_nc"]}

    day_set = set(iso_f)
    sums = {}
    for r in D["cat_records"]:
        rl1, rgrp, rday, rcl, rim, rpu, rva, rprs, rprr, rnp = r
        if rl1 != l1_filter or rday not in day_set:
            continue
        key = (rday, rgrp)
        if key not in sums:
            sums[key] = {"cl":0,"im":0,"pu":0,"va":0,"prs":0,"prr":0,"np":0}
        b = sums[key]
        b["cl"]+=rcl;b["im"]+=rim;b["pu"]+=rpu;b["va"]+=rva
        b["prs"]+=rprs;b["prr"]+=rprr;b["np"]+=rnp

    def mk_ser(grp):
        out = {k:[] for k in ["clicks","impr","ctr","pr","purch","val"]}
        for day in iso_f:
            b = sums.get((day, grp))
            if not b or b["np"] == 0:
                for k in out: out[k].append(None)
                continue
            out["clicks"].append(round(b["cl"]/b["np"],4))
            out["impr"].append(round(b["im"]/b["np"],2))
            out["ctr"].append(round(b["cl"]/b["im"]*100,4) if b["im"]>0 else None)
            out["pr"].append(round(b["prs"]/b["prr"]*100,4) if b["prr"]>0 else None)
            out["purch"].append(round(b["pu"]/b["np"],5))
            out["val"].append(round(b["va"]/b["np"],2))
        return out

    return {"labels":lab_f,"iso":iso_f,"opt":mk_ser("opt"),"nc":mk_ser("nc"),
            "n_opt":D["n_opt"],"n_nc":D["n_nc"]}


def get_yoy_series(YOY, iso_list, metric):
    om = YOY["opt"].get(metric, {})
    nm = YOY["nc"].get(metric, {})
    return [om.get(d) for d in iso_list], [nm.get(d) for d in iso_list]


def period_avg(series):
    v = [x for x in series if x is not None]
    return sum(v)/len(v) if v else None


